/// @nodoc
class OverrideType {
  static const semanticOverride = OverrideType._('SEMANTIC_OVERRIDE');
  static const summaryOverride = OverrideType._('SUMMARY_OVERRIDE');
  static const userPreferenceOverride =
      OverrideType._('USER_PREFERENCE_OVERRIDE');
  static const selfManaged = OverrideType._('SELF_MANAGED');
  static const episodicOverride = OverrideType._('EPISODIC_OVERRIDE');

  final String value;

  const OverrideType._(this.value);

  static const values = [
    semanticOverride,
    summaryOverride,
    userPreferenceOverride,
    selfManaged,
    episodicOverride
  ];

  static OverrideType fromString(String value) => values
      .firstWhere((e) => e.value == value, orElse: () => OverrideType._(value));

  @override
  bool operator ==(other) => other is OverrideType && other.value == value;

  @override
  int get hashCode => value.hashCode;

  @override
  String toString() => value;
}

