    required this.skills,
    required this.status,
    required this.systemPrompt,
    required this.tools,
    required this.truncation,
    required this.updatedAt,
    this.authorizerConfiguration,
    this.environmentArtifact,
    this.environmentVariables,
    this.failureReason,
    this.maxIterations,
    this.maxTokens,
    this.memory,
    this.timeoutSeconds,
  });

  factory Harness.fromJson(Map<String, dynamic> json) {
