          .toList(),
      arn: (json['arn'] as String?) ?? '',
      createdAt: nonNullableTimeStampFromJson(json['createdAt'] ?? 0),
      environment: HarnessEnvironmentProvider.fromJson(
          (json['environment'] as Map<String, dynamic>?) ??
              const <String, dynamic>{}),
      executionRoleArn: (json['executionRoleArn'] as String?) ?? '',
      harnessId: (json['harnessId'] as String?) ?? '',
      harnessName: (json['harnessName'] as String?) ?? '',
      model: HarnessModelConfiguration.fromJson(
          (json['model'] as Map<String, dynamic>?) ??
              const <String, dynamic>{}),
      skills: ((json['skills'] as List?) ?? const [])
          .nonNulls
          .map((e) => HarnessSkill.fromJson(e as Map<String, dynamic>))
          .toList(),
      status: HarnessStatus.fromString((json['status'] as String?) ?? ''),
      systemPrompt: ((json['systemPrompt'] as List?) ?? const [])
          .nonNulls
          .map((e) =>
              HarnessSystemContentBlock.fromJson(e as Map<String, dynamic>))
          .toList(),
      tools: ((json['tools'] as List?) ?? const [])
          .nonNulls
          .map((e) => HarnessTool.fromJson(e as Map<String, dynamic>))
          .toList(),
      truncation: HarnessTruncationConfiguration.fromJson(
          (json['truncation'] as Map<String, dynamic>?) ??
              const <String, dynamic>{}),
      updatedAt: nonNullableTimeStampFromJson(json['updatedAt'] ?? 0),
      authorizerConfiguration: json['authorizerConfiguration'] != null
          ? AuthorizerConfiguration.fromJson(
              json['authorizerConfiguration'] as Map<String, dynamic>)
          : null,
      environmentArtifact: json['environmentArtifact'] != null
          ? HarnessEnvironmentArtifact.fromJson(
              json['environmentArtifact'] as Map<String, dynamic>)
          : null,
      environmentVariables:
          (json['environmentVariables'] as Map<String, dynamic>?)
              ?.map((k, e) => MapEntry(k, e as String)),
      failureReason: json['failureReason'] as String?,
      maxIterations: json['maxIterations'] as int?,
      maxTokens: json['maxTokens'] as int?,
