/// An OAuth credential provider for gateway authentication. This structure
/// contains the configuration for authenticating with the target endpoint using
/// OAuth.
///
/// @nodoc
class OAuthCredentialProvider {
  /// The Amazon Resource Name (ARN) of the OAuth credential provider. This ARN
  /// identifies the provider in Amazon Web Services.
  final String providerArn;

  /// The OAuth scopes for the credential provider. These scopes define the level
  /// of access requested from the OAuth provider.
  final List<String> scopes;

  /// The custom parameters for the OAuth credential provider. These parameters
  /// provide additional configuration for the OAuth authentication process.
  final Map<String, String>? customParameters;

  /// The URL where the end user's browser is redirected after obtaining the
  /// authorization code. Generally points to the customer's application.
  final String? defaultReturnUrl;

  /// Specifies the kind of credentials to use for authorization:
  ///
  /// <ul>
  /// <li>
  /// <code>CLIENT_CREDENTIALS</code> - Authorization with a client ID and secret.
  /// </li>
  /// <li>
  /// <code>AUTHORIZATION_CODE</code> - Authorization with a token that is
  /// specific to an individual end user.
  /// </li>
  /// <li>
  /// <code>TOKEN_EXCHANGE</code> - Authorization using on-behalf-of token
  /// exchange. An inbound user token is exchanged for a downstream access token
  /// scoped to the target audience.
  /// </li>
  /// </ul>
  final OAuthGrantType? grantType;

  OAuthCredentialProvider({
    required this.providerArn,
    required this.scopes,
    this.customParameters,
    this.defaultReturnUrl,
    this.grantType,
  });

  factory OAuthCredentialProvider.fromJson(Map<String, dynamic> json) {
    return OAuthCredentialProvider(
      providerArn: (json['providerArn'] as String?) ?? '',
      scopes: ((json['scopes'] as List?) ?? const [])
          .nonNulls
          .map((e) => e as String)
          .toList(),
      customParameters: (json['customParameters'] as Map<String, dynamic>?)
          ?.map((k, e) => MapEntry(k, e as String)),
      defaultReturnUrl: json['defaultReturnUrl'] as String?,
      grantType: (json['grantType'] as String?)?.let(OAuthGrantType.fromString),
    );
  }

  Map<String, dynamic> toJson() {
    final providerArn = this.providerArn;
    final scopes = this.scopes;
    final customParameters = this.customParameters;
    final defaultReturnUrl = this.defaultReturnUrl;
    final grantType = this.grantType;
    return {
      'providerArn': providerArn,
      'scopes': scopes,
      if (customParameters != null) 'customParameters': customParameters,
      if (defaultReturnUrl != null) 'defaultReturnUrl': defaultReturnUrl,
      if (grantType != null) 'grantType': grantType.value,
    };
  }
}

